import{hasDependency}from"../../util/plugin.js";import{findWebpackDependenciesFromConfig}from"../webpack/index.js";const title="Rspack",enablers=["@rspack/core"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),config=["rspack.config*.{js,ts,mjs,mts,cjs,cts}"],resolveConfig=async(e,n)=>(await findWebpackDependenciesFromConfig(e,n)).filter(e=>!e.specifier.startsWith("builtin:")),plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveConfig:resolveConfig};export default plugin;